     1→/**
     2→ * PM Schedule Management Routes
     3→ *
     4→ * REST endpoints for PM schedule CRUD operations and history.
     5→ * Wraps PMSchedulerService with HTTP interface per spec 005.5.
     6→ *
     7→ * Endpoints:
     8→ * - GET /pm/schedule - List schedules with filtering
     9→ * - GET /pm/schedule/:id - Get PM by ID
    10→ * - POST /pm/schedule - Create new PM schedule
    11→ * - PATCH /pm/schedule/:id - Update PM (reschedule, reassign)
    12→ * - POST /pm/schedule/:id/lock - Lock PM to prevent optimizer changes
    13→ * - POST /pm/schedule/:id/unlock - Unlock PM to allow optimizer changes
    14→ * - GET /pm/schedule/:id/history - Get change history
    15→ *
    16→ * @see specs/005-api.md Section 5.5
    17→ */
    18→
    19→import { Hono } from 'hono';
    20→import { eq, and, gte, lte, isNull, count, desc } from 'drizzle-orm';
    21→import type { SQL } from 'drizzle-orm';
    22→import {
    23→  success,
    24→  paginatedSuccess,
    25→  error,
    26→  parsePaginationQuery,
    27→  ErrorCodes,
    28→  type AppVariables,
    29→} from '../types';
    30→import { getRequestId, getRequestDuration } from '../middleware/request-context';
    31→import { getPMSchedulerService, type SchedulePmRequest, type MovePmRequest } from '../../services';
    32→import { isValidUuid } from '../../lib/schemas';
    33→import { db } from '../../lib/db/connection';
    34→import { pmSchedule } from '../../lib/db/schema';
    35→
    36→let pmSchedulerService: ReturnType<typeof getPMSchedulerService> | null = null;
    37→
    38→function getService(): ReturnType<typeof getPMSchedulerService> {
    39→  if (!pmSchedulerService) {
    40→    pmSchedulerService = getPMSchedulerService();
    41→  }
    42→  return pmSchedulerService;
    43→}
    44→
    45→export const pmScheduleRoutes = new Hono<{ Variables: AppVariables }>();
    46→
    47→/**
    48→ * GET /pm/schedule
    49→ *
    50→ * List PM schedules with filtering and pagination.
    51→ *
    52→ * Query Parameters:
    53→ * - trainId: Filter by train
    54→ * - depotId: Filter by assigned depot
    55→ * - pmTypeId: Filter by PM type
    56→ * - status: Filter by status (SCHEDULED, IN_PROGRESS, COMPLETED, DEFERRED, CANCELLED)
    57→ * - fromDate: Target date from (inclusive)
    58→ * - toDate: Target date to (inclusive)
    59→ * - scenarioId: Get scenario schedule (null/omitted = production)
    60→ */
    61→pmScheduleRoutes.get('/pm/schedule', async (c) => {
    62→  // Parse query filters
    63→  const trainId = c.req.query('trainId');
    64→  const depotId = c.req.query('depotId');
    65→  const pmTypeId = c.req.query('pmTypeId');
    66→  const status = c.req.query('status');
    67→  const fromDate = c.req.query('fromDate');
    68→  const toDate = c.req.query('toDate');
    69→  const scenarioId = c.req.query('scenarioId');
    70→
    71→  // Build filter conditions
    72→  const conditions: SQL<unknown>[] = [];
    73→
    74→  if (trainId && isValidUuid(trainId)) {
    75→    conditions.push(eq(pmSchedule.trainId, trainId));
    76→  }
    77→  if (depotId && isValidUuid(depotId)) {
    78→    conditions.push(eq(pmSchedule.assignedDepotId, depotId));
    79→  }
    80→  if (pmTypeId && isValidUuid(pmTypeId)) {
    81→    conditions.push(eq(pmSchedule.pmTypeId, pmTypeId));
    82→  }
    83→  if (status) {
    84→    const validStatuses = ['SCHEDULED', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED', 'CANCELLED'] as const;
    85→    if (validStatuses.includes(status as typeof validStatuses[number])) {
    86→      conditions.push(eq(pmSchedule.status, status as typeof validStatuses[number]));
    87→    }
    88→  }
    89→  if (fromDate) {
    90→    conditions.push(gte(pmSchedule.targetDate, fromDate));
    91→  }
    92→  if (toDate) {
    93→    conditions.push(lte(pmSchedule.targetDate, toDate));
    94→  }
    95→
    96→  // Handle scenario filter
    97→  if (scenarioId && isValidUuid(scenarioId)) {
    98→    conditions.push(eq(pmSchedule.scenarioId, scenarioId));
    99→  } else {
   100→    // Default to production schedule (scenarioId is NULL)
   101→    conditions.push(isNull(pmSchedule.scenarioId));
   102→  }
   103→
   104→  // Parse pagination
   105→  const pagination = parsePaginationQuery({
   106→    page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   107→    pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   108→    sort: c.req.query('sort'),
   109→  });
   110→
   111→  // Count total items
   112→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   113→  const totalResult = await db
   114→    .select({ count: count() })
   115→    .from(pmSchedule)
   116→    .where(whereClause);
   117→  const totalItems = totalResult[0]?.count ?? 0;
   118→
   119→  // Query with relations
   120→  const schedules = await db.query.pmSchedule.findMany({
   121→    where: whereClause,
   122→    with: {
   123→      train: true,
   124→      pmType: true,
   125→      assignedDepot: true,
   126→      assignedTrack: true,
   127→    },
   128→    orderBy: desc(pmSchedule.targetDate),
   129→    limit: pagination.pageSize,
   130→    offset: pagination.offset,
   131→  });
   132→
   133→  // Map to API response format
   134→  const data = schedules.map((pm) => ({
   135→    id: pm.id,
   136→    train: pm.train
   137→      ? {
   138→          id: pm.train.id,
   139→          trainNumber: pm.train.trainNumber,
   140→          fleetCode: pm.train.fleetId, // TODO: Get fleet code from relation
   141→        }
   142→      : null,
   143→    pmType: pm.pmType
   144→      ? {
   145→          id: pm.pmType.id,
   146→          code: pm.pmType.pmCode,
   147→          name: pm.pmType.pmName,
   148→          estimatedHours: pm.pmType.estimatedHours,
   149→        }
   150→      : null,
   151→    targetDate: pm.targetDate,
   152→    targetMileageKm: pm.targetMileageKm,
   153→    status: pm.status,
   154→    constraintStart: pm.constraintStart,
   155→    constraintEnd: pm.constraintEnd,
   156→    assignedDepot: pm.assignedDepot
   157→      ? {
   158→          id: pm.assignedDepot.id,
   159→          code: pm.assignedDepot.code,
   160→        }
   161→      : null,
   162→    assignedTrack: pm.assignedTrack
   163→      ? {
   164→          id: pm.assignedTrack.id,
   165→          trackNumber: pm.assignedTrack.trackNumber,
   166→          trackType: pm.assignedTrack.trackType,
   167→        }
   168→      : null,
   169→    assignedHours: pm.assignedHours ? Number(pm.assignedHours) : null,
   170→    isLocked: pm.isLocked ?? false,
   171→    maximoWoId: pm.maximoWoId,
   172→  }));
   173→
   174→  return c.json(
   175→    paginatedSuccess(
   176→      data,
   177→      {
   178→        page: pagination.page,
   179→        pageSize: pagination.pageSize,
   180→        totalItems,
   181→      },
   182→      { durationMs: getRequestDuration(c) }
   183→    )
   184→  );
   185→});
   186→
   187→/**
   188→ * GET /pm/schedule/:id
   189→ *
   190→ * Get PM schedule details by ID.
   191→ */
   192→pmScheduleRoutes.get('/pm/schedule/:id', async (c) => {
   193→  const requestId = getRequestId(c);
   194→  const pmId = c.req.param('id');
   195→
   196→  if (!isValidUuid(pmId)) {
   197→    return c.json(error(ErrorCodes.VALIDATION_ERROR, 'Invalid PM schedule ID format', requestId), 400);
   198→  }
   199→
   200→  const service = getService();
   201→  const pmResult = await service.getPm(pmId);
   202→
   203→  // Cast to include all query relations (service returns more than type declares)
   204→  const pm = pmResult as typeof pmResult & {
   205→    assignedDepot: { id: string; code: string; name: string } | null;
   206→  };
   207→
   208→  // Check material availability for upcoming PMs
   209→  let materialStatus = { allAvailable: true, warnings: [] as string[] };
   210→  if (pm.status === 'SCHEDULED' && pm.assignedDepotId) {
   211→    try {
   212→      const materialResult = await service.checkMaterialAvailability(
   213→        pm.pmTypeId,
   214→        pm.assignedDepotId,
   215→        pm.targetDate
   216→      );
   217→      materialStatus = {
   218→        allAvailable: !materialResult.isBlocked && materialResult.softConstraintWarnings.length === 0,
   219→        warnings: [
   220→          ...materialResult.hardConstraintViolations.map((v) => `Blocked: ${v.partNumber} (need ${v.requiredQuantity}, have ${v.availableQuantity})`),
   221→          ...materialResult.softConstraintWarnings.map((v) => `Warning: ${v.partNumber} may not be available`),
   222→        ],
   223→      };
   224→    } catch {
   225→      // Material check failed, assume available
   226→    }
   227→  }
   228→
   229→  return c.json(
   230→    success({
   231→      id: pm.id,
   232→      train: pm.train
   233→        ? {
   234→            id: pm.train.id,
   235→            trainNumber: pm.train.trainNumber,
   236→            fleetId: pm.train.fleetId,
