     2→ * Error Handler Middleware
     3→ *
     4→ * Centralized error handling for all API errors.
     5→ * Maps MMS error classes to appropriate HTTP status codes and response formats.
     6→ *
     7→ * @see specs/005-api.md for error response format
     8→ */
     9→
    10→import type { Context, ErrorHandler, NotFoundHandler } from 'hono';
    11→import { HTTPException } from 'hono/http-exception';
    12→import { error, ErrorCodes, type AppVariables } from '../types';
    13→import { logger } from '../../lib/logging/logger';
    14→import {
    15→  MmsError,
    16→  ValidationError,
    17→  NotFoundError,
    18→  ConflictError,
    19→  AuthenticationError,
    20→  AuthorizationError,
    21→  MaximoLockError,
    22→  ComplianceWindowError,
    23→  TrackConflictError,
    24→  MaterialConstraintError,
    25→  ServiceDemandViolationError,
    26→  DatabaseError,
    27→  ExternalServiceError,
    28→  ServiceUnavailableError,
    29→} from '../../lib/errors';
    30→
    31→/**
    32→ * Map MMS error to HTTP status code
    33→ */
    34→function getStatusCode(err: Error): number {
    35→  if (err instanceof HTTPException) {
    36→    return err.status;
    37→  }
    38→
    39→  if (err instanceof ValidationError) return 400;
    40→  if (err instanceof AuthenticationError) return 401;
    41→  if (err instanceof AuthorizationError) return 403;
    42→  if (err instanceof NotFoundError) return 404;
    43→  if (err instanceof ConflictError) return 409;
    44→  if (err instanceof MaximoLockError) return 409;
    45→  if (err instanceof ComplianceWindowError) return 422;
    46→  if (err instanceof TrackConflictError) return 422;
    47→  if (err instanceof MaterialConstraintError) return 422;
    48→  if (err instanceof ServiceDemandViolationError) return 422;
    49→  if (err instanceof ServiceUnavailableError) return 503;
